var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치자, 이내 따뜻한 온기가 당신의 몸을 감싸는 것이 느껴졌다.","JPN":"心の準備を終えると、やがて暖かい温もりがあなたの体を包む。","ENG":"As you gathered your resolve, a warm sensation quickly enveloped your body.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"……음?","JPN":"……うん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"괜찮아? 정신이 들어!?","JPN":"大丈夫？　気がついた！？","ENG":"You good? How are you holding up?","TWN":"還好嗎？你醒了嗎？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"다행이다… 다행이야…….","JPN":"よかった……よかったよ……","ENG":"Thank goodness... I'm so relieved...","TWN":"太好了…沒事就好……."},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"걱정했단 말이야! 어쩌면 당신이 이대로 눈을 뜨지 않으면 나는 어떻게 해야 할까 해서…….","JPN":"心配したんだよ！　もしあなたがこのまま目覚めなかったら、私はどうしたらいいのかなって……","ENG":"I was so worried! I kept thinking, what if you never woke up... What would I do then...?","TWN":"我很擔心你！萬一你就這樣再也睜不開眼睛，那我該怎麼辦……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"으음? 내가 당신을 왜 끌어안고 있냐고……?","JPN":"うん？　どうして私があなたを抱きしめているのかって……？","ENG":"Huh? You're wondering why I'm embracing you...?","TWN":"嗯？你問我為什麼抱著你……？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"뭐, 뭐, 뭐, 뭐, 뭐……!?","JPN":"な、な、な、な、なっ……！？","ENG":"W-w-w-whaaaaat...?!","TWN":"什、什、什、什、什麼……！？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"뭘 그렇게 부끄러워하는 건데? 차, 착각하지 말라고……!","JPN":"なによそんなに恥ずかしがって。ごっ、誤解しないでよね……！","ENG":"What are you so embarrassed about? D-don't get the wrong idea...!","TWN":"你害羞什麼？你、你可別誤會……！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"당신을 끌어안고 있었던 건… 어디까지나 체온이 너무 떨어지면 위험하니까…….","JPN":"あなたを抱きしめていたのは……あくまでも体温が下がっちゃうと大変だから……","ENG":"The reason I was embracing you... was purely because it's dangerous if your temperature falls too low...","TWN":"我之所以會抱著你…是因為我怕你失溫會有生命危險……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"그, 그래서… 당신이 죽을 까봐… 잠시 살을 맞대고 있었을 뿐이라고……!","JPN":"そ、それで……あなたが死なないように……ちょっとくっついてただけなんだよ……！","ENG":"A-actually... I was worried you'd die... So I was just holding on to you for a moment, okay...?","TWN":"我、我怕你會死掉…所以才暫時抱著你取暖而已……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"지금 내 몸은 남들보다 훨씬 따뜻할 테니까…….","JPN":"私の体は今、他の人よりずっとあったかいはずだから……","ENG":"My body is a lot warmer than others right now, so...","TWN":"畢竟我現在的體溫應該比別人高很多……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"뭐, 뭐야! 너무 그렇게 웃지 말라고! 웃다가 상처 벌어져도 책임 못 진다?","JPN":"な、なんだよ！　そんなに笑わないでよ！　笑って傷口が開いても責任取ってあげないからね！","ENG":"W-what?! Stop laughing like that! I won't be responsible if your wound tears open!","TWN":"你、你幹嘛！笑那麼開心幹嘛！笑得太用力裂開我可不負責喔！？"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"여기까지 왔는데, 당신마저 멋대로 죽어버리면 곤란하다고!","JPN":"ここまで来たのに、あなたまで勝手に死んじゃうと困るんだよ！","ENG":"We've come this far, so don't you dare die on me now!","TWN":"好不容易撐到現在，我可不准你就這樣死掉！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"이왕 이렇게 된 거, 마지막까지 살아서 날 책임져 달란 말이야!","JPN":"もうこうなったから、最後まで生きて私のこと一生責任取りなさいよ！","ENG":"Now that it's come to this, stay alive and take responsibility for me until the end!","TWN":"事情變成這樣，你要給我活到最後對我負責！"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"걱정했다고… 정말이야…….","JPN":"心配したんだよ……本当に……","ENG":"I was really worried... I mean it...","TWN":"我很擔心你…是真的……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"당신의 손… 역시 크고 따뜻하네…….","JPN":"あなたの手……やっぱり大きくてあったかい……","ENG":"Your hands... They really are big and warm as expected...","TWN":"你的手…還是一樣大又溫暖……"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"기억나? 당신이 나에게 가르쳐 주었잖아.","JPN":"覚えてる？　あなたが私に教えてくれたじゃない。","ENG":"Do you remember? You were the one who taught me.","TWN":"你還記得嗎？你曾經告訴過我。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_SPECIAL","text":{"KOREA":"강해서 살아남는 게 아니라, 살아남는 게 강한 거라고.","JPN":"強いからって生き残れるわけじゃなくて、生き残るから強いんだって。","ENG":"That being strong does not guarantee survival. But survival proves that you're strong.","TWN":"不是強者才能活下來，而是活下來的才是強者。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_YOO_MI_NA_SPECIAL_01","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_SPECIAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};